    fontSize: 13,
  },
  dishRow: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 4,
  },
  dishInfo: {
    fontSize: 13,
    fontFamily: 'Poppins-Regular',
  },
  cardFooter: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: spacing.md,
    borderTopWidth: 1,
  },
  totalLabel: {
    fontSize: 12,
    fontFamily: 'Poppins-Regular',
    marginBottom: 2,
